  "data": {
    "database": "ercot_db",
    "query": "SELECT \n  COUNT(*) as total_records,\n  MIN(timestamp) as first_timestamp,\n  MAX(timestamp) as last_timestamp,\n  EXTRACT(HOUR FROM MIN(timestamp)) as sample_hour,\n  EXTRACT(MINUTE FROM MIN(timestamp)) as sample_minute\nFROM ercot_lmp \nWHERE zone_name = 'houston' \n  AND zone_type = 'hub'\n  AND is_day_ahead = false\n  AND EXTRACT(YEAR FROM timestamp) = 2024\n  AND EXTRACT(MONTH FROM timestamp) IN (6, 7, 8)",
    "columns": [
      "total_records",
      "first_timestamp",
